SELECT COUNT(*) AS total_move_operations
FROM operations
WHERE operation_type = 'Move' AND status = 'Completed';

SELECT operation_type, status
FROM operations
WHERE status = 'Completed';

SELECT COUNT(*) AS total_completed_operations
FROM operations
WHERE status = 'Completed' AND created_at BETWEEN '2023-01-01' AND '2023-01-31';

SELECT COUNT(operation_id) AS total_move_operations
FROM operations
WHERE sol_id = 1 AND operation_type = 'Move';

SELECT COUNT(node_id) AS total_nodes, node_name
FROM nodes
GROUP BY node_name;

SELECT COUNT(operation_id) AS total_active_operations
FROM operations
WHERE status = 'In Progress';
